// ffhash.c - حساب بصمة (hash) لمحتوى مقروء عبر FFmpeg
#include <libavutil/avutil.h>
#include <stdio.h>
#include <string.h>

int main(int argc, char **argv) {
    const char *input = argc > 1 ? argv[1] : "input.bin";
    uint8_t buf[4096];
    size_t total = 0;

    FILE *fp = fopen(input, "rb");
    if (!fp) {
        fprintf(stderr, "فشل فتح الملف\n");
        return 1;
    }

    // قراءة كل الملف وحساب البصمة
    unsigned int hash = 0;
    while ((total = fread(buf, 1, sizeof(buf), fp)) > 0) {
        for (size_t i = 0; i < total; i++) {
            hash = hash * 31 + buf[i];
        }
    }
    fclose(fp);

    printf("File: %s\n", input);
    printf("Size: %zu bytes\n", total);
    printf("Hash: %u\n", hash);
    printf("Hash (hex): %08x\n", hash);
    return 0;
}

